effect.shader:
void main() {
    float actualOffset = offset + 0.05;
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    texColor.rgb *= stepCount;
    texColor.rgb += actualOffset;
    texColor.rgb = floor(texColor.rgb);
    texColor.rgb -= actualOffset;
    texColor.rgb /= stepCount;
    gl_FragColor = texColor;
}
